'use client';

import { useState, useEffect } from 'react';
import Link from 'next/link';

export default function UserProfile() {
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [userId, setUserId] = useState('');

  useEffect(() => {
    // Check if user is logged in (from localStorage)
    const storedUserId = localStorage.getItem('userId');
    if (storedUserId) {
      //setIsLoggedIn(true);
      //setUserId(storedUserId);
    }
  }, []);

  const handleLogout = () => {
    // Clear localStorage
    localStorage.removeItem('userId');
    // Update state
    setIsLoggedIn(false);
    setUserId('');
  };

  return (
    <div className="flex items-center gap-3 rounded-lg bg-gray-200 px-4 py-2">
      {/* User Avatar/Image */}
      <div className="flex h-10 w-10 items-center justify-center rounded-full bg-gray-400 font-bold text-white">
        👤
      </div>

      {/* User ID or Login Text */}
      {isLoggedIn ? (
        <div className="flex items-center gap-3">
          <span className="text-sm font-medium text-gray-800">{userId}</span>
          <button
            onClick={handleLogout}
            className="text-sm font-medium text-red-800 transition hover:text-red-800"
          >
            Logout
          </button>
        </div>
      ) : (
        <Link href="/login">
          <span className="cursor-pointer text-sm font-medium text-blue-600 hover:text-blue-800">
            Login
          </span>
        </Link>
      )}
    </div>
  );
}
